// src/components/ProductList.js

// components/ProductList.js
import React from 'react';

const ProductList = ({ products }) => {
    return (
        <div>
            <h2>Lista de Produtos</h2>
            <ul>
                {products.length > 0 ? (
                    products.map((product) => (
                        <li key={product.codigo} style={{ marginBottom: '10px' }}>
                            <div style={{ border: '1px solid #ccc', padding: '10px', borderRadius: '5px' }}>
                                <strong>Nome:</strong> {product.nome} <br />
                                <strong>Descrição:</strong> {product.descricao} <br />
                                <strong>Código:</strong> {product.codigo} <br />
                                <strong>Categoria:</strong> {product.categoria} <br />
                                <strong>Preço:</strong> R$ {parseFloat(product.preco).toFixed(2)} <br />
                                <strong>Quantidade Mínima:</strong> {product.quantidade_minima}
                            </div>
                        </li>
                    ))
                ) : (
                    <li>Nenhum produto encontrado.</li>
                )}
            </ul>
        </div>
    );
};

export default ProductList;
